import requests as requests
import json
import pprint

def lambda_handler(event, context):
    print(f"The following event was received: {event}")
    
    try :
        URL = event['url']
        payload = event['payload']
        response  = requests.request("POST", URL , data=json.dumps({'payload': payload}), headers={'content-type':'application/json'})
        
        pprint.pprint(response)
        
    except Exception as e:
      raise e